async function atomicFileCreateLock(lockPath: string, ttlMs: number): Promise<{ release: () => void } | null> {
  const fs = await import("node:fs/promises");
  try {
    const fd = await fs.open(lockPath, "wx");
    return { release: () => fd.close().catch(()=>{}).then(()=>fs.unlink(lockPath).catch(()=>{})) };
  } catch (err: any) {
    if (err.code !== "EEXIST") throw err;
    // Check TTL
    const stat = await fs.stat(lockPath).catch(() => null);
    if (stat && Date.now() - stat.mtimeMs > ttlMs) {
      await fs.unlink(lockPath).catch(()=>{});
      const fd = await fs.open(lockPath, "wx").catch(()=>null);
      if (fd) return { release: ... };
    }
    return null;
  }
}
