  const entitlement: DioEntitlement = {...from provision...};
  await saveDioEntitlement(storage, entitlement);
  await saveProvisioningRecord(storage, { ...provision, status: "completed" });
  await completeEvent(storage, payload.id, true);
  return {...};
}

if (provision?.status === "provisioning") {
  // Still provisioning. With idempotency key we could retry, but to keep it
  // simple, return in-progress. Creem will retry; eventually it completes or
  // goes stale.
  await completeEvent(storage, payload.id, false, "Provisioning already in progress");
  throw createError({ statusCode: 409, statusMessage: "Provisioning already in progress" });
}

