```ts
async function acquireFsLock(storage: Storage, key: string): Promise<{ release: () => Promise<void> } | null> {
  const mount = storage.getMount?.(key);
  const driverName = mount?.driver?.name;
  if (driverName !== "fs" && driverName !== "fs-lite") return null;

  // Get base path from driver options
  const basePath = mount.driver.options?.base;
  if (!basePath || typeof basePath !== "string") return null;

  const lockPath = `${basePath}/${key}.lock`;

  const fs = await import("node:fs/promises");
  try {
    const fd = await fs.open(lockPath, "wx");
    return {
      release: async () => {
        await fd.close().catch(() => {});
        await fs.unlink(lockPath).catch(() => {});
      },
    };
  } catch (err: any) {
    if (err.code !== "EEXIST") throw err;
    // Check TTL on lock file
    const stat = await fs.stat(lockPath).catch(() => null);
    if (stat && Date.now() - stat.mtimeMs > EVENT_LOCK_TTL_MS) {
      await fs.unlink(lockPath).catch(() => {});
      const fd = await fs.open(lockPath, "wx").catch(() => null);
      if (fd) {
        return {
          release: async () => {
            await fd.close().catch(() => {});
            await fs.unlink(lockPath).catch(() => {});
          },
        };
      }
    }
    return null;
  }
}
```

