 	const [otp, setOtp] = useState("");
 	const [requiresOtp, setRequiresOtp] = useState(false);
 	const [devCode, setDevCode] = useState("");
 	const [loading, setLoading] = useState(false);
 	const [error, setError] = useState("");

 	useEffect(() => {
 		const sync = () => {
 			setRequest(activeDioPrompt);
 			setEmail("");
 			setMode("purchase");
 			setApiKey("");
