 			setPurchaseReference(result.purchaseReference);
 			window.open(result.checkoutUrl, "_blank", "noopener,noreferrer");
 		} catch (err) {
 			setError(err instanceof Error ? err.message : String(err));
 		} finally {
 			setLoading(false);
