 				setError(otp ? "Invalid or expired code." : "Enter the verification code sent to your email.");
 			} else {
 				setError("No active access found for this email.");
 			}
 		} catch (err) {
 			setError(err instanceof Error ? err.message : String(err));
 		} finally {
 			setLoading(false);
 		}
 	};

 	return (
