 	const otp = generateOtp();
 	const challenge: RecoveryChallenge = {
 		email,
 		otpHash: hashOtp(otp),
 		expiresAt: new Date(Date.now() + 15 * 60 * 1000).toISOString(),
 		attempts: 0,
 	};
 	await storage.setItem(recoveryStorageKey(email), challenge);
 	return otp;
 }

